// SoxlDivisionStrategy.java (@Component implements TradingStrategy)
BigDecimal A = balance.avgPrice() != null ? balance.avgPrice() : currentPrice;
int Q = balance.soxlQty();
BigDecimal M = A.multiply(valueOf(Q));
BigDecimal D = balance.effectiveAmt();
BigDecimal B = D.add(M);
BigDecimal K = B.divide(valueOf(20), 2, HALF_UP);
int T = Q == 0 ? 0 : M.divide(K, 0, DOWN).intValue();
BigDecimal S = valueOf(20 - T * 2).divide(valueOf(100), 4, HALF_UP);
BigDecimal P = A.multiply(valueOf(1.2)).setScale(2, HALF_UP);

