@Service TradingService implements ExecuteTradingUseCase {
  void execute() throws InterruptedException {
    DstInfo dst = DstInfo.calculate();
    Thread.sleep(dst.waitUntilLocDeadline());  // LOC 마감까지 대기
    String token = kisTokenPort.getToken();
    if (!kisHolidayPort.isMarketOpen(token, today())) {
      notifyPort.notifyMarketClosed(); return;
    }
    AccountBalance balance = kisAccountPort.getBalance(token);
    if (balance.shouldSkip()) {
      notifyPort.notifyInsufficientBalance(balance); return;
    }
    BigDecimal price = kisPricePort.getPrice(token, 'SOXL');
    TradingVariables vars = strategy.calculate(balance, price);
    List<Order> mainOrders = executeMainOrders(token, vars);

    // n8n 원본 Wait 40min 노드 기준: LOC 마감 후 40분 대기
    Thread.sleep(dst.waitUntilPostClose());  // postClose = locDeadline + 40min

    List<Execution> executions = kisExecutionPort.getExecutions(token);
    List<Order> corrections = correctionStrategy.calculate(vars, executions, token);
    TradingReport report = TradingReport.of(vars, mainOrders, corrections);
    tradeHistoryPort.save(toHistory(mainOrders));
    tradeHistoryPort.save(toHistory(corrections));
    portfolioSnapshotPort.save(toSnapshot(balance, price));
    notifyPort.notifyReport(report);
  }
}

